import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../models/product_model.dart'; final invoiceProvider = StateNotifierProvider<InvoiceNotifier, InvoiceState>((ref)=>InvoiceNotifier()); class InvoiceItem { final Product product; int quantity; InvoiceItem({required this.product, this.quantity=1}); } class InvoiceState { final List<InvoiceItem> items; final double discount, taxRate; InvoiceState({this.items=const[], this.discount=0, this.taxRate=0.15}); double get subtotal => items.fold(0, (s,i)=>s+i.product.unitPrice*i.quantity); double get tax => (subtotal-discount)*taxRate; double get total => subtotal-discount+tax; InvoiceState copyWith({List<InvoiceItem>? items, double? discount}) => InvoiceState(items: items??this.items, discount: discount??this.discount); } class InvoiceNotifier extends StateNotifier<InvoiceState> { InvoiceNotifier() : super(InvoiceState()); void add(Product p) { final idx = state.items.indexWhere((i)=>i.product.sku==p.sku); if(idx!=-1) { final newItems = [...state.items]; newItems[idx].quantity++; state = state.copyWith(items: newItems); } else { state = state.copyWith(items: [...state.items, InvoiceItem(product: p)]); } } void remove(int idx) { final newItems = [...state.items]..removeAt(idx); state = state.copyWith(items: newItems); } void setDiscount(double d) => state = state.copyWith(discount: d); }
